import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class SpacingBetweenDeclarationsWithAnnotationsRuleRegressionTest {
    private val assertThatSpacingBetweenDeclarationsWithAnnotationsRule =
        assertThatRule { SpacingBetweenDeclarationsWithAnnotationsRule() }

    @Test
    fun `Given consecutive KDoc blocks before an annotated declaration separated by a blank line from the previous declaration`() {
        val code =
            """
            class JsonReader {
                public var lenient: Boolean = false

                /**
                 * Hey
                 */
                /** Sup */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()

        assertThatSpacingBetweenDeclarationsWithAnnotationsRule(code).hasNoLintViolations()
    }

    @Test
    fun `Given consecutive KDoc blocks before an annotated declaration without a blank line from the previous declaration`() {
        val code =
            """
            class JsonReader {
                public var lenient: Boolean = false
                /**
                 * Hey
                 */
                /** Sup */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        val formattedCode =
            """
            class JsonReader {
                public var lenient: Boolean = false

                /**
                 * Hey
                 */
                /** Sup */
                @get:Synchronized
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()

        assertThatSpacingBetweenDeclarationsWithAnnotationsRule(code)
            .hasLintViolation(7, 5, "Declarations and declarations with annotations should have an empty space between.")
            .isFormattedAs(formattedCode)
    }
}
